-- ملء محتوى عنقود "الفرائض والمواريث" (fara-mawarith) — أربعة تصنيفات
-- فرعية، جميعها draft (استنفاد كامل للعنقود): مقدمات الفرائض، أصحاب
-- الفروض والعصبات، الحجب والتعصيب، المناسخات والتطبيقات العملية.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس usul-fiqh/qawaid-fiqhiyya/
-- wilaya-islamiyya (تعريفي موجز: قسم body + قسم examples).
-- المصدر المعتمد المسمّى لكل الدروس الأربعة: "المواريث في الشريعة
-- الإسلامية في ضوء الكتاب والسنة" — محمد علي الصابوني (كتاب متخصص
-- في علم الفرائض تحديدًا).
-- حديث واحد استُشهد به، تحقَّق حرفياً عبر WebSearch قبل الإدراج (متفق
-- عليه): "ألحقوا الفرائض بأهلها فما تركت الفرائض فلأولى رجل ذكر"
-- (البخاري 6732 ومسلم 1615، عن ابن عباس).
-- ثلاث آيات تحقَّقت حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: النساء 11، النساء 12، النساء 176.
-- المثال العددي في درس المناسخات حساب أصلي مطابق للمنهج القياسي في علم
-- الفرائض (تصحيح ثم جامعة)، تحقَّقت مجاميعه يدويًا (480 سهمًا).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) مقدمات الفرائض
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a6071eea-bd42-4bc1-ac78-6b67c7ad362f' AND title='مقدمات علم الفرائض: التعريف وأسباب الإرث وشروطه وموانعه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مقدمات علم الفرائض: التعريف وأسباب الإرث وشروطه وموانعه', 'تعريف موجز بعلم الفرائض وأسباب الإرث الثلاثة وشروطه وموانعه', 'a6071eea-bd42-4bc1-ac78-6b67c7ad362f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف علم الفرائض وأسبابه وشروطه وموانعه', 'علم الفرائض هو العلم الذي يُعرَف به من يرث ومن لا يرث، ومقدار نصيب كل وارث، وكيفية توزيع التركة على مستحقيها. وسُمِّي بذلك لأن الشريعة قدَّرت أنصبة الورثة تقديرًا محكمًا لا مجال فيه للاجتهاد أو النقصان أو الزيادة، خلافًا لغيره من أبواب الفقه التي تخضع لاجتهاد المجتهدين. وللإرث ثلاثة أسباب: النكاح، وهو الزوجية القائمة حقيقةً حال الوفاة؛ والنسب، وهو القرابة بالولادة مباشرة أو بواسطة؛ والولاء، وهو عصوبة المعتِق على عتيقه. ويُشترط لثبوت الإرث ثلاثة شروط: تحقق موت المورِّث موتًا حقيقيًّا أو حكميًّا كالمفقود الذي يُحكم بموته، وتحقق حياة الوارث عند موت المورِّث ولو للحظة واحدة، والعلم بجهة الإرث وترتيبها. أما موانع الإرث فأشهرها ثلاثة: الرق، إذ لا يرث العبد ولا يُورَث لأن ماله لسيده؛ والقتل، فقاتل مورِّثه عمدًا عدوانًا لا يرثه عقوبةً له؛ واختلاف الدين، فلا يرث المسلم الكافر ولا الكافر المسلم.', 1),
    (v_lesson, 'examples', 'الأصل القرآني لتقدير الأنصبة', 'قال تعالى: ﴿يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ ۖ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنثَيَيْنِ ۚ فَإِن كُنَّ نِسَاءً فَوْقَ اثْنَتَيْنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَ ۖ وَإِن كَانَتْ وَاحِدَةً فَلَهَا النِّصْفُ ۚ وَلِأَبَوَيْهِ لِكُلِّ وَاحِدٍ مِّنْهُمَا السُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُ وَلَدٌ ۚ فَإِن لَّمْ يَكُن لَّهُ وَلَدٌ وَوَرِثَهُ أَبَوَاهُ فَلِأُمِّهِ الثُّلُثُ ۚ فَإِن كَانَ لَهُ إِخْوَةٌ فَلِأُمِّهِ السُّدُسُ ۚ مِن بَعْدِ وَصِيَّةٍ يُوصِي بِهَا أَوْ دَيْنٍ ۗ آبَاؤُكُمْ وَأَبْنَاؤُكُمْ لَا تَدْرُونَ أَيُّهُمْ أَقْرَبُ لَكُمْ نَفْعًا ۚ فَرِيضَةً مِّنَ اللَّهِ ۚ إِنَّ اللَّهَ كَانَ عَلِيمًا حَكِيمًا﴾ (النساء: 11). ختمت الآية بقوله: ﴿فَرِيضَةً مِّنَ اللَّهِ﴾، وهي التسمية التي استمد منها هذا العلم اسمه: فالأنصبة فريضة محكمة من الله لا اجتهاد فيها، وقد فُصِّل في هذه الآية وحدها أربعة من الفروض الستة المقررة: النصف والثلثان للبنات، والسدس لكل من الأبوين مع الفرع الوارث، والثلث للأم عند عدمه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المواريث في الشريعة الإسلامية في ضوء الكتاب والسنة — محمد علي الصابوني', 1);
  END IF;

  -- 2) أصحاب الفروض والعصبات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='75a6ede0-b498-4ad8-a794-b8d46b4275cc' AND title='أصحاب الفروض والعصبات: الفروض الستة وأنواع العصبة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أصحاب الفروض والعصبات: الفروض الستة وأنواع العصبة', 'تعريف بأصحاب الفروض الستة المقدرة وأنواع العصبات الثلاثة', '75a6ede0-b498-4ad8-a794-b8d46b4275cc', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الفروض الستة وأصحابها، وأنواع العصبة', 'أصحاب الفروض هم الورثة الذين قدَّر لهم الشرع نصيبًا معينًا من التركة لا يزيد ولا ينقص إلا بأسباب محددة، وفروضهم ستة: النصف والربع والثمن والثلثان والثلث والسدس. فالنصف فرض البنت المنفردة، وبنت الابن عند عدم الفرع الوارث الأعلى منها، والأخت الشقيقة أو لأب المنفردة، والزوج عند عدم الفرع الوارث لزوجته. والربع فرض الزوج مع الفرع الوارث، والزوجة أو الزوجات عند عدمه. والثمن فرض الزوجة أو الزوجات مع الفرع الوارث. والثلثان فرض البنتين فأكثر، والأختين الشقيقتين أو لأب فأكثر عند عدم من يعصبهن. والثلث فرض الأم عند عدم الفرع الوارث وعدم اثنين فأكثر من الإخوة، وفرض الإخوة لأم إذا تعددوا ولو كانوا اثنين. والسدس فرض الأب والأم كل على حدة مع الفرع الوارث، والجدة عند عدم الأم، والأخ أو الأخت لأم منفردًا. أما العصبات فهم من يرثون بلا تقدير، يأخذون ما أبقته الفروض أو التركة كلها عند عدم أصحاب فروض، وينقسمون إلى: عصبة بالنفس كالابن والأب والأخ الشقيق، وعصبة بالغير كالبنت تصير عصبة بأخيها، وعصبة مع الغير كالأخت الشقيقة تعصّب مع البنت.', 1),
    (v_lesson, 'examples', 'الحديث والآية الجامعان بين الفروض والعصبة', 'عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «ألحقوا الفرائض بأهلها، فما تركت الفرائض فلأولى رجل ذكر» (متفق عليه: البخاري 6732 ومسلم 1615)، وهو الأصل الجامع الذي يميّز بين نوعي الورثة: أصحاب الفروض الذين يُعطَون نصيبهم المقدَّر أولاً، والعصبة الذين يستحقون ما بقي بعدهم. وقال تعالى في تفصيل بعض الفروض: ﴿وَلَكُمْ نِصْفُ مَا تَرَكَ أَزْوَاجُكُمْ إِن لَّمْ يَكُن لَّهُنَّ وَلَدٌ ۚ فَإِن كَانَ لَهُنَّ وَلَدٌ فَلَكُمُ الرُّبُعُ مِمَّا تَرَكْنَ ۚ مِن بَعْدِ وَصِيَّةٍ يُوصِينَ بِهَا أَوْ دَيْنٍ ۚ وَلَهُنَّ الرُّبُعُ مِمَّا تَرَكْتُمْ إِن لَّمْ يَكُن لَّكُمْ وَلَدٌ ۚ فَإِن كَانَ لَكُمْ وَلَدٌ فَلَهُنَّ الثُّمُنُ مِمَّا تَرَكْتُم ۚ مِّن بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَا أَوْ دَيْنٍ ۗ وَإِن كَانَ رَجُلٌ يُورَثُ كَلَالَةً أَوِ امْرَأَةٌ وَلَهُ أَخٌ أَوْ أُخْتٌ فَلِكُلِّ وَاحِدٍ مِّنْهُمَا السُّدُسُ ۚ فَإِن كَانُوا أَكْثَرَ مِن ذَٰلِكَ فَهُمْ شُرَكَاءُ فِي الثُّلُثِ ۚ مِن بَعْدِ وَصِيَّةٍ يُوصَىٰ بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ ۚ وَصِيَّةً مِّنَ اللَّهِ ۗ وَاللَّهُ عَلِيمٌ حَلِيمٌ﴾ (النساء: 12)، وفيها أربعة من الفروض الستة مجتمعة: النصف والربع للزوج، والربع والثمن للزوجة، والسدس والثلث للإخوة لأم عند الانفراد والتعدد.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المواريث في الشريعة الإسلامية في ضوء الكتاب والسنة — محمد علي الصابوني', 1);
  END IF;

  -- 3) الحجب والتعصيب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='448ee12e-ceba-4ceb-830d-7cab3812aab8' AND title='الحجب والتعصيب: أنواع الحجب وترتيب العصبة بالنفس') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الحجب والتعصيب: أنواع الحجب وترتيب العصبة بالنفس', 'تعريف بنوعي الحجب (حرمان ونقصان) وترتيب العصبة بالنفس', '448ee12e-ceba-4ceb-830d-7cab3812aab8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أنواع الحجب وضابطه، وترتيب العصبة بالنفس', 'الحجب في اصطلاح الفرائض: منع من قام به سبب الإرث من الميراث كله أو من أوفر حظَّيه، لوجود وارث آخر أقرب أو أولى منه. وينقسم إلى نوعين: حجب حرمان، وهو المنع الكلي من الميراث، كحجب الجد بالأب، وحجب الأخ الشقيق بالابن أو الأب؛ وحجب نقصان، وهو تخفيض النصيب المقدَّر دون إسقاطه بالكلية، كنقصان نصيب الزوج من النصف إلى الربع بوجود الفرع الوارث، ونقصان نصيب الأم من الثلث إلى السدس بوجود الفرع الوارث أو اثنين فأكثر من الإخوة. وضابط حجب الحرمان أنه لا يلحق إلا الحاشية (كالإخوة وبني الإخوة) أو من يُدلي بواسطة (كالجد مع وجود الأب)، أما الأصول والفروع المباشرون كالأبوين والأولاد فلا يُحجبون حجب حرمان بالكلية وإنما يُحجبون حجب نقصان فقط. أما ترتيب العصبة بالنفس فهو: البنوة، الابن فابنه وإن نزل؛ فالأبوة، الأب فالجد وإن علا؛ فالإخوة، الشقيق فلأب فبنوهم؛ فالعمومة، العم الشقيق فلأب فبنوهم؛ ويُقدَّم الأقرب درجة فالأقرب عند اجتماع أكثر من جهة.', 1),
    (v_lesson, 'examples', 'مثال قرآني على التعصيب مع الغير وأثر الحجب', 'قال تعالى: ﴿يَسْتَفْتُونَكَ قُلِ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ ۚ إِنِ امْرُؤٌ هَلَكَ لَيْسَ لَهُ وَلَدٌ وَلَهُ أُخْتٌ فَلَهَا نِصْفُ مَا تَرَكَ ۚ وَهُوَ يَرِثُهَا إِن لَّمْ يَكُن لَّهَا وَلَدٌ ۚ فَإِن كَانَتَا اثْنَتَيْنِ فَلَهُمَا الثُّلُثَانِ مِمَّا تَرَكَ ۚ وَإِن كَانُوا إِخْوَةً رِّجَالًا وَنِسَاءً فَلِلذَّكَرِ مِثْلُ حَظِّ الْأُنثَيَيْنِ ۗ يُبَيِّنُ اللَّهُ لَكُمْ أَن تَضِلُّوا ۗ وَاللَّهُ بِكُلِّ شَيْءٍ عَلِيمٌ﴾ (النساء: 176)، وهي مثال دقيق على التعصيب مع الغير وأثر الحجب معًا: فالأخت الشقيقة أو لأب تستقل بالنصف عند انفرادها، فإذا حضر معها أخ صار الاثنان عصبة يقتسمان الباقي للذكر مثل حظ الأنثيين، وهو ما يحجبها عن استقلالها بالفرض المقدَّر ويحوّلها إلى عصبة مع أخيها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المواريث في الشريعة الإسلامية في ضوء الكتاب والسنة — محمد علي الصابوني', 1);
  END IF;

  -- 4) المناسخات والتطبيقات العملية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1f8c330d-d099-4e49-8069-61cdcf32bd68' AND title='المناسخات: تعريفها وطريقة حلها بمثال تطبيقي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المناسخات: تعريفها وطريقة حلها بمثال تطبيقي', 'تعريف بالمناسخة في الفرائض وطريقة حلها الحسابية مع مثال عملي', '1f8c330d-d099-4e49-8069-61cdcf32bd68', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف المناسخة وطريقة حلها', 'المناسخة في الفرائض: أن يموت وارث من ورثة الميت الأول قبل قسمة تركته، فيصبح نصيبه فيها تركة جديدة تُقسَّم بدورها على ورثته هو. وطريقة حلها أن تُحل مسألة الميت الأول وتُصحَّح بحيث تنقسم سهامها على جميع ورثته بلا كسر، ثم تُحل مسألة الميت الثاني مستقلةً بين ورثته الأحياء وتُصحَّح كذلك، ثم يُنظر بين نصيب الميت الثاني في المسألة الأولى وأصل مسألته الثانية: فإن انقسم عليها من غير كسر اكتُفي بمسألة واحدة جامعة، وإن لم ينقسم طُلب التوافق أو المباينة بينهما، وضُربت مسألة الميت الثاني أو وفقها في المسألة الأولى أو وفقها، فينتج عدد يسمى «الجامعة» تُقسَّم عليه أنصبة جميع الورثة الأحياء من الطرفين.', 1),
    (v_lesson, 'examples', 'مثال تطبيقي على حل المناسخة', 'مثال: توفي رجل عن زوجة وابنين وبنت، فأصل مسألته من ثمانية، للزوجة الثمن سهم واحد، ولا ينقسم الباقي وهو سبعة على الأبناء الثلاثة بنسبة اثنين واثنين وواحد بلا كسر، فصُحِّحت المسألة بضرب أصلها في خمسة فصارت من أربعين: للزوجة خمسة، ولكل ابن أربعة عشر، وللبنت سبعة. ثم توفي أحد الابنين قبل القسمة عن زوجته وابنه وأمه، وهي زوجة الميت الأول نفسها، فأصل مسألته الثانية من أربعة وعشرين: لأمه السدس أربعة، ولزوجته الثمن ثلاثة، والباقي سبعة عشر لابنه بالتعصيب. ولمَّا لم ينقسم نصيبه في المسألة الأولى، وهو أربعة عشر، على مسألته الثانية، وهي أربعة وعشرون، بلا كسر، وكان بينهما توافق بالنصف، ضُرب وفق إحداهما، وهو اثنا عشر، في المسألة الأولى فنتجت جامعة قدرها أربعمائة وثمانون سهمًا: تأخذ الزوجة الأولى نصيبها كزوجة للميت الأول وكأم للميت الثاني معًا فيكون ثمانية وثمانين سهمًا، ويأخذ الابن الحي مائة وثمانية وستين سهمًا، والبنت أربعة وثمانين سهمًا، وزوجة الابن المتوفى واحدًا وعشرين سهمًا، وابنه مائة وتسعة عشر سهمًا.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المواريث في الشريعة الإسلامية في ضوء الكتاب والسنة — محمد علي الصابوني', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
